import face_recognition
from flask import Flask, request, jsonify
import os
import pickle

app = Flask(__name__)

# Load the known employee photos and their labels
known_images = []
labels = []
for filename in os.listdir('employee_photos'):
    image = face_recognition.load_image_file(os.path.join('employee_photos', filename))
    encoding = face_recognition.face_encodings(image)[0]
    labels.append(filename.split('.')[0])
    known_images.append(encoding)

# Train the model on the known employee photos
model = face_recognition.face_encodings(known_images[0])

@app.route('/recognize', methods=['POST'])
def recognize():
    if request.method == 'POST':
        image = request.files['image']
        encoding = face_recognition.face_encodings(face_recognition.load_image_file(image))[0]
        results = face_recognition.compare_faces(model, encoding)
        confidence_scores = {}
        for i, result in enumerate(results):
            if result:
                confidence_scores[labels[i]] = 1.0
            else:
                confidence_scores[labels[i]] = 0.0

        # Get the detailed probability distribution over all known faces
        output_image = face_recognition.face_distance(model, encoding)
        confidence_scores.update(dict(zip(labels, output_image)))

        return jsonify({'confidence_scores': confidence_scores})

if __name__ == '__main__':
    app.run(debug=True)